import { Layer } from '@vis.gl/react-maplibre';
import { type ReactNode } from 'react';

import {
  DEFAULT_ICON_SIZE_RATIO,
  ICON_BACKGROUND_OPACITY,
} from '../../constants.js';
import { MapShape } from '../../types/shapes.js';

interface BackgroundSymbolLayerProps {
  background: boolean;
  beforeId: string;
  source: string;
  radius: number;
  iconAnchor: 'bottom' | 'center';
  symbolName: string;
  layerId?: string;
  shape?: string | MapShape | ReactNode;
}

export const BackgroundSymbolLayer = (props: BackgroundSymbolLayerProps) => {
  const { background, beforeId, source, radius, symbolName, layerId } = props;

  return (
    <Layer
      id={layerId}
      type="symbol"
      source={source}
      beforeId={beforeId}
      layout={{
        'icon-image': symbolName,
        'icon-size': 1,
        'icon-rotation-alignment': 'viewport',
        'icon-rotate': ['get', '__bearing'],
        'icon-allow-overlap': true,
        'icon-offset': [0, -(radius * DEFAULT_ICON_SIZE_RATIO)],
      }}
      paint={{
        'icon-color': [
          'case',
          ['boolean', ['feature-state', 'hover'], false],
          ['get', '__hoveredBackgroundColor'],
          ['get', '__backgroundColor'],
        ],
        'icon-opacity': [
          'case',
          ['boolean', background, false],
          ICON_BACKGROUND_OPACITY,
          ['boolean', ['feature-state', 'hover'], false],
          ICON_BACKGROUND_OPACITY,
          0,
        ],
      }}
    />
  );
};
